INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 200, 150, '{}' FROM labs l WHERE l.slug = 'network-tunneling' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R2', 'router', 'Cisco ISR 4331', 500, 150, '{}' FROM labs l WHERE l.slug = 'network-tunneling' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R2');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Create tunnel interface', E'On **R1**, create a Tunnel0 interface.', 'interface Tunnel0', 'Tunnel interfaces are virtual — they encapsulate packets inside another protocol.', 'R1', ARRAY['configure terminal', 'interface Tunnel0'], 'command', 10 FROM labs l WHERE l.slug = 'network-tunneling' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Set tunnel source and destination', E'Configure the tunnel source as Gi0/0 and destination as 203.0.113.2.', 'tunnel source / tunnel destination', 'The outer header uses these endpoints for delivery across the transport network.', 'R1', ARRAY['tunnel source GigabitEthernet0/0', 'tunnel destination 203.0.113.2'], 'command', 15 FROM labs l WHERE l.slug = 'network-tunneling' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Assign tunnel IP', E'Assign IP 10.255.0.1/30 to the Tunnel0 interface on **R1**.', 'ip address 10.255.0.1 255.255.255.252', 'The tunnel IP is used for routing over the tunnel — separate from the transport IPs.', 'R1', ARRAY['ip address 10.255.0.1 255.255.255.252'], 'command', 10 FROM labs l WHERE l.slug = 'network-tunneling' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 200, 150, '{}' FROM labs l WHERE l.slug = 'gre-tunnels' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R2', 'router', 'Cisco ISR 4331', 500, 150, '{}' FROM labs l WHERE l.slug = 'gre-tunnels' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R2');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Create GRE tunnel', E'On **R1**, create Tunnel0 and set tunnel mode to GRE.', 'interface Tunnel0 → tunnel mode gre ip', 'GRE is the default tunnel mode on Cisco IOS.', 'R1', ARRAY['configure terminal', 'interface Tunnel0', 'tunnel mode gre ip'], 'command', 10 FROM labs l WHERE l.slug = 'gre-tunnels' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Configure tunnel endpoints', E'Set tunnel source to Gi0/0 and destination to 198.51.100.2 on **R1**.', 'tunnel source/destination', 'GRE adds a 24-byte header (4 GRE + 20 new IP) to each encapsulated packet.', 'R1', ARRAY['tunnel source GigabitEthernet0/0', 'tunnel destination 198.51.100.2'], 'command', 10 FROM labs l WHERE l.slug = 'gre-tunnels' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Verify tunnel status', E'Check the tunnel interface status on **R1**.', 'show interfaces tunnel 0', 'The tunnel should show up/up when both source and destination are reachable.', 'R1', ARRAY['show interfaces tunnel 0'], 'command', 10 FROM labs l WHERE l.slug = 'gre-tunnels' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 150, 150, '{"asn":65001}' FROM labs l WHERE l.slug = 'autonomous-systems' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R2', 'router', 'Cisco ISR 4331', 450, 150, '{"asn":65001}' FROM labs l WHERE l.slug = 'autonomous-systems' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R2');
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'ISP', 'router', 'Cisco ISR 4451', 300, 300, '{"asn":65000}' FROM labs l WHERE l.slug = 'autonomous-systems' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'ISP');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Configure iBGP within AS', E'On **R1**, set up iBGP peering with R2 (both in AS 65001).', 'neighbor R2-IP remote-as 65001', 'iBGP peers share the same AS number. They don''t change the AS path.', 'R1', ARRAY['configure terminal', 'router bgp 65001', 'neighbor 10.0.0.2 remote-as 65001'], 'command', 15 FROM labs l WHERE l.slug = 'autonomous-systems' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Configure eBGP to ISP', E'On **R1**, add eBGP peering with the ISP (AS 65000).', 'neighbor ISP-IP remote-as 65000', 'eBGP peers are in different ASes and prepend their AS to the path.', 'R1', ARRAY['neighbor 10.1.0.1 remote-as 65000'], 'command', 15 FROM labs l WHERE l.slug = 'autonomous-systems' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Verify BGP summary', E'Check BGP neighbor status on **R1**.', 'show ip bgp summary', 'The State/PfxRcd column shows how many prefixes were received from each peer.', 'R1', ARRAY['show ip bgp summary'], 'command', 10 FROM labs l WHERE l.slug = 'autonomous-systems' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 300, 150, '{}' FROM labs l WHERE l.slug = 'ipv6-addressing' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Enable IPv6 routing', E'Enable IPv6 unicast routing on **R1**.', 'ipv6 unicast-routing', 'IPv6 routing is disabled by default on Cisco routers.', 'R1', ARRAY['configure terminal', 'ipv6 unicast-routing'], 'command', 10 FROM labs l WHERE l.slug = 'ipv6-addressing' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Configure IPv6 address', E'Assign 2001:DB8:1::1/64 to Gi0/0 on **R1**.', 'ipv6 address 2001:DB8:1::1/64', 'IPv6 global unicast addresses are the equivalent of IPv4 public addresses.', 'R1', ARRAY['interface GigabitEthernet0/0', 'ipv6 address 2001:DB8:1::1/64'], 'command', 10 FROM labs l WHERE l.slug = 'ipv6-addressing' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Verify IPv6 interfaces', E'Check IPv6 addresses on all interfaces.', 'show ipv6 interface brief', 'Each interface gets a link-local (FE80::) address automatically plus any configured globals.', 'R1', ARRAY['show ipv6 interface brief'], 'command', 10 FROM labs l WHERE l.slug = 'ipv6-addressing' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'FW1', 'firewall', 'Cisco ASA 5516', 300, 100, '{}' FROM labs l WHERE l.slug = 'remote-access-vpn' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'FW1');
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'REMOTE', 'workstation', 'Laptop', 300, 300, '{}' FROM labs l WHERE l.slug = 'remote-access-vpn' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'REMOTE');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Configure ISAKMP policy', E'On **FW1**, create an ISAKMP policy with AES-256 encryption.', 'crypto isakmp policy 10', 'ISAKMP Phase 1 establishes a secure channel for negotiating IPsec parameters.', 'FW1', ARRAY['configure terminal', 'crypto isakmp policy 10', 'encryption aes 256'], 'command', 15 FROM labs l WHERE l.slug = 'remote-access-vpn' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Create transform set', E'Define an IPsec transform set using ESP with AES and SHA.', 'crypto ipsec transform-set', 'Transform sets define the encryption and authentication algorithms for data packets.', 'FW1', ARRAY['crypto ipsec transform-set MYSET esp-aes esp-sha-hmac'], 'command', 15 FROM labs l WHERE l.slug = 'remote-access-vpn' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Verify IPsec SA', E'Check the ISAKMP security associations.', 'show crypto isakmp sa', 'QM_IDLE state means Phase 1 is complete and the tunnel is active.', 'FW1', ARRAY['show crypto isakmp sa'], 'command', 10 FROM labs l WHERE l.slug = 'remote-access-vpn' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4321', 300, 150, '{}' FROM labs l WHERE l.slug = 'ssh-secure-mgmt' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Set hostname and domain', E'On **R1**, set hostname and domain name (required for RSA key generation).', 'hostname R1 → ip domain-name lab.local', 'RSA keys use the FQDN (hostname.domain) as part of the key identity.', 'R1', ARRAY['configure terminal', 'hostname R1', 'ip domain-name lab.local'], 'command', 10 FROM labs l WHERE l.slug = 'ssh-secure-mgmt' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Generate RSA keys', E'Generate 2048-bit RSA keys on **R1**.', 'crypto key generate rsa modulus 2048', '2048 bits is the minimum recommended key size for SSH version 2.', 'R1', ARRAY['crypto key generate rsa modulus 2048'], 'command', 10 FROM labs l WHERE l.slug = 'ssh-secure-mgmt' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Restrict VTY to SSH', E'Configure VTY lines 0-4 to accept only SSH connections.', 'transport input ssh under line vty', 'This blocks insecure Telnet access to the management plane.', 'R1', ARRAY['line vty 0 4', 'transport input ssh', 'login local'], 'command', 15 FROM labs l WHERE l.slug = 'ssh-secure-mgmt' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 4, 'Verify SSH', E'Verify SSH is enabled on **R1**.', 'show ip ssh', 'SSH version 2.0 should be enabled with the configured RSA key size.', 'R1', ARRAY['show ip ssh'], 'command', 10 FROM labs l WHERE l.slug = 'ssh-secure-mgmt' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 300, 150, '{}' FROM labs l WHERE l.slug = 'acl-traffic-filtering' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Create named extended ACL', E'On **R1**, create an extended ACL named BLOCK-TELNET.', 'ip access-list extended BLOCK-TELNET', 'Named ACLs are easier to manage than numbered ones — you can edit individual entries.', 'R1', ARRAY['configure terminal', 'ip access-list extended BLOCK-TELNET'], 'command', 10 FROM labs l WHERE l.slug = 'acl-traffic-filtering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Add deny and permit rules', E'Deny TCP port 23 (Telnet) from any source, then permit all other traffic.', 'deny tcp any any eq 23 → permit ip any any', 'ACLs are processed top-down. The implicit deny at the end blocks everything not explicitly permitted.', 'R1', ARRAY['deny tcp any any eq 23', 'permit ip any any'], 'command', 15 FROM labs l WHERE l.slug = 'acl-traffic-filtering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Apply ACL to interface', E'Apply BLOCK-TELNET inbound on Gi0/0.', 'ip access-group BLOCK-TELNET in', 'ACLs are applied per-interface, per-direction (in or out).', 'R1', ARRAY['interface GigabitEthernet0/0', 'ip access-group BLOCK-TELNET in'], 'command', 10 FROM labs l WHERE l.slug = 'acl-traffic-filtering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 4, 'Verify ACL', E'Check the ACL configuration and hit counts.', 'show access-lists', 'Match counts help you verify the ACL is working and see which rules are being triggered.', 'R1', ARRAY['show access-lists'], 'command', 10 FROM labs l WHERE l.slug = 'acl-traffic-filtering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 300, 150, '{}' FROM labs l WHERE l.slug = 'nat-configuration' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Mark inside interface', E'On **R1**, mark Gi0/0 as the NAT inside interface.', 'ip nat inside', 'Inside interfaces face the private network. Outside interfaces face the public network.', 'R1', ARRAY['configure terminal', 'interface GigabitEthernet0/0', 'ip nat inside'], 'command', 10 FROM labs l WHERE l.slug = 'nat-configuration' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Mark outside interface', E'Mark Gi0/1 as the NAT outside interface.', 'ip nat outside', 'NAT translates addresses as packets cross the inside/outside boundary.', 'R1', ARRAY['interface GigabitEthernet0/1', 'ip nat outside'], 'command', 10 FROM labs l WHERE l.slug = 'nat-configuration' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Configure static NAT', E'Create a static NAT mapping: inside 10.0.1.100 to outside 203.0.113.100.', 'ip nat inside source static ...', 'Static NAT creates a permanent one-to-one mapping, useful for servers.', 'R1', ARRAY['ip nat inside source static 10.0.1.100 203.0.113.100'], 'command', 15 FROM labs l WHERE l.slug = 'nat-configuration' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 4, 'Verify NAT translations', E'Check the NAT translation table.', 'show ip nat translations', 'The translation table shows active mappings between inside local and inside global addresses.', 'R1', ARRAY['show ip nat translations'], 'command', 10 FROM labs l WHERE l.slug = 'nat-configuration' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 300, 150, '{}' FROM labs l WHERE l.slug = 'pat-overload' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 1, 'Create ACL for NAT traffic', E'On **R1**, create access-list 1 permitting the 10.0.1.0/24 subnet.', 'access-list 1 permit 10.0.1.0 0.0.0.255', 'The ACL defines which inside addresses are eligible for translation.', 'R1', ARRAY['configure terminal', 'access-list 1 permit 10.0.1.0 0.0.0.255'], 'command', 10 FROM labs l WHERE l.slug = 'pat-overload' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 2, 'Configure PAT overload', E'Configure PAT using the outside interface with overload.', 'ip nat inside source list 1 interface Gi0/1 overload', 'Overload (PAT) maps many inside hosts to one outside IP using unique port numbers.', 'R1', ARRAY['ip nat inside source list 1 interface GigabitEthernet0/1 overload'], 'command', 15 FROM labs l WHERE l.slug = 'pat-overload' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
INSERT INTO lab_steps (lab_id, step_number, title, instruction, hint, explanation, target_device, expected_commands, validation_type, points) SELECT l.id, 3, 'Verify PAT translations', E'Check the translation table to see port mappings.', 'show ip nat translations', 'PAT entries show different source ports mapped to the same outside IP.', 'R1', ARRAY['show ip nat translations'], 'command', 10 FROM labs l WHERE l.slug = 'pat-overload' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
INSERT INTO devices (lab_id, name, device_type, model, x_pos, y_pos, properties) SELECT l.id, 'AP1', 'wireless_ap', 'Cisco Aironet 3800', 300, 150, '{}' FROM labs l WHERE l.slug = 'wireless-ap-config' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'AP1');
