-- ============================================================
-- MIGRATION: Add devices and steps for all labs missing them
-- Safe to run multiple times (uses INSERT ... ON CONFLICT / WHERE NOT EXISTS)
-- ============================================================

-- Helper: only insert device if it doesn't exist for that lab
-- We use a CTE pattern: INSERT WHERE NOT EXISTS

-- ============================================================
-- STP Lab
-- ============================================================
SELECT l.id, 'SW1', 'switch', 'Cisco 3560', 200, 150, '{"ios":"15.2","ports":24}'
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'SW1');
SELECT l.id, 'SW2', 'switch', 'Cisco 3560', 500, 150, '{"ios":"15.2","ports":24}'
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'SW2');
SELECT l.id, 'SW3', 'switch', 'Cisco 2960', 350, 300, '{"ios":"15.2","ports":24}'
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'SW3');

SELECT l.id, 1, 'Verify default STP state', E'On **SW1**, check the current spanning-tree status for VLAN 1.', 'show spanning-tree', 'STP elects a root bridge based on the lowest bridge ID (priority + MAC).', 'SW1', ARRAY['show spanning-tree'], 'command', 10
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
SELECT l.id, 2, 'Set SW1 as root bridge', E'Configure **SW1** with priority 4096 to force it as the root bridge for VLAN 1.', 'spanning-tree vlan 1 priority 4096', 'Lower priority = more likely to become root. Default is 32768.', 'SW1', ARRAY['configure terminal', 'spanning-tree vlan 1 priority 4096'], 'command', 15
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
SELECT l.id, 3, 'Enable PortFast on access ports', E'On **SW2**, enable PortFast on interface Gi0/1 to skip the listening/learning states.', 'spanning-tree portfast on the interface', 'PortFast immediately transitions access ports to forwarding, reducing boot time for end devices.', 'SW2', ARRAY['configure terminal', 'interface GigabitEthernet0/1', 'spanning-tree portfast'], 'command', 10
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
SELECT l.id, 4, 'Enable BPDU Guard', E'On **SW2** Gi0/1, enable BPDU Guard to shut down the port if a switch is connected.', 'spanning-tree bpduguard enable', 'BPDU Guard protects PortFast ports by errdisabling them if BPDUs are received.', 'SW2', ARRAY['spanning-tree bpduguard enable'], 'command', 10
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);
SELECT l.id, 5, 'Verify STP topology', E'Check the spanning-tree on **SW3** to verify port roles (Root, Designated, Blocking).', 'show spanning-tree', 'Non-root switches have root ports (toward root) and may have blocking ports to prevent loops.', 'SW3', ARRAY['show spanning-tree'], 'command', 10
FROM labs l WHERE l.slug = 'stp-loop-prevention' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 5);

-- ============================================================
-- OSPF Lab
-- ============================================================
SELECT l.id, 'R1', 'router', 'Cisco ISR 4321', 150, 150, '{"ios":"16.9"}' FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
SELECT l.id, 'R2', 'router', 'Cisco ISR 4321', 450, 150, '{"ios":"16.9"}' FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R2');
SELECT l.id, 'R3', 'router', 'Cisco ISR 4321', 300, 300, '{"ios":"16.9"}' FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R3');

SELECT l.id, 1, 'Enable OSPF on R1', E'Enter OSPF configuration on **R1** with process ID 1.', 'router ospf 1', 'OSPF process IDs are locally significant — they don''t need to match across routers.', 'R1', ARRAY['configure terminal', 'router ospf 1'], 'command', 10 FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
SELECT l.id, 2, 'Advertise R1 networks', E'Advertise the 10.0.1.0/24 network into OSPF area 0 on **R1**.', 'network 10.0.1.0 0.0.0.255 area 0', 'The network command uses wildcard masks (inverse of subnet mask). Area 0 is the backbone.', 'R1', ARRAY['network 10.0.1.0 0.0.0.255 area 0'], 'command', 10 FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
SELECT l.id, 3, 'Configure OSPF on R2', E'Enable OSPF process 1 on **R2** and advertise 10.0.2.0/24 in area 0.', 'router ospf 1 then network command', 'All routers in the same area exchange LSAs to build an identical LSDB.', 'R2', ARRAY['configure terminal', 'router ospf 1', 'network 10.0.2.0 0.0.0.255 area 0'], 'command', 10 FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
SELECT l.id, 4, 'Configure OSPF on R3', E'Enable OSPF process 1 on **R3** and advertise 10.0.3.0/24 in area 0.', 'Same pattern as R1 and R2', 'Once all routers are in the same area, OSPF calculates the shortest path tree using Dijkstra''s algorithm.', 'R3', ARRAY['configure terminal', 'router ospf 1', 'network 10.0.3.0 0.0.0.255 area 0'], 'command', 10 FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);
SELECT l.id, 5, 'Verify OSPF neighbors', E'On **R1**, verify OSPF neighbor adjacencies have formed.', 'show ip ospf neighbor', 'FULL state means adjacency is complete and LSDBs are synchronized.', 'R1', ARRAY['show ip ospf neighbor'], 'command', 10 FROM labs l WHERE l.slug = 'ospf-single-area' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 5);

-- ============================================================
-- LACP Lab
-- ============================================================
SELECT l.id, 'SW1', 'switch', 'Cisco 3850', 200, 150, '{"ports":48}' FROM labs l WHERE l.slug = 'lacp-etherchannel' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'SW1');
SELECT l.id, 'SW2', 'switch', 'Cisco 3850', 500, 150, '{"ports":48}' FROM labs l WHERE l.slug = 'lacp-etherchannel' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'SW2');

SELECT l.id, 1, 'Select interfaces for bundling', E'On **SW1**, enter interface range Gi0/1-2 to configure both ports for the EtherChannel.', 'interface range GigabitEthernet0/1-2', 'EtherChannel bundles multiple physical links into one logical link for bandwidth and redundancy.', 'SW1', ARRAY['configure terminal', 'interface range GigabitEthernet0/1-2'], 'command', 10 FROM labs l WHERE l.slug = 'lacp-etherchannel' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
SELECT l.id, 2, 'Configure LACP active mode', E'Set the channel-group to 1 with LACP active mode on **SW1**.', 'channel-group 1 mode active', 'LACP active mode initiates negotiation. Both sides can be active, or one active and one passive.', 'SW1', ARRAY['channel-group 1 mode active'], 'command', 15 FROM labs l WHERE l.slug = 'lacp-etherchannel' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
SELECT l.id, 3, 'Configure SW2 matching LACP', E'On **SW2**, configure the same interface range with channel-group 1 mode active.', 'Same commands as SW1', 'Both ends must be in the same channel-group number and use compatible LACP modes.', 'SW2', ARRAY['configure terminal', 'interface range GigabitEthernet0/1-2', 'channel-group 1 mode active'], 'command', 15 FROM labs l WHERE l.slug = 'lacp-etherchannel' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
SELECT l.id, 4, 'Verify EtherChannel', E'On **SW1**, verify the EtherChannel is up and bundled.', 'show etherchannel summary', 'Look for (P) flags indicating ports are bundled in the port-channel.', 'SW1', ARRAY['show etherchannel summary'], 'command', 10 FROM labs l WHERE l.slug = 'lacp-etherchannel' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);

-- ============================================================
-- DHCP Lab
-- ============================================================
SELECT l.id, 'R1', 'router', 'Cisco ISR 4321', 300, 100, '{"ios":"16.9"}' FROM labs l WHERE l.slug = 'dhcp-server-config' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
SELECT l.id, 'PC1', 'workstation', 'Desktop', 300, 300, '{"os":"Linux"}' FROM labs l WHERE l.slug = 'dhcp-server-config' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'PC1');

SELECT l.id, 1, 'Exclude reserved addresses', E'On **R1**, exclude addresses 10.0.1.1 through 10.0.1.10 from the DHCP pool.', 'ip dhcp excluded-address 10.0.1.1 10.0.1.10', 'Excluding addresses prevents the DHCP server from assigning IPs reserved for routers, servers, etc.', 'R1', ARRAY['configure terminal', 'ip dhcp excluded-address 10.0.1.1 10.0.1.10'], 'command', 10 FROM labs l WHERE l.slug = 'dhcp-server-config' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
SELECT l.id, 2, 'Create DHCP pool', E'Create a DHCP pool named "LAN" on **R1** with network 10.0.1.0/24.', 'ip dhcp pool LAN → network 10.0.1.0 255.255.255.0', 'Each DHCP pool defines a range of addresses and options to distribute to clients.', 'R1', ARRAY['ip dhcp pool LAN', 'network 10.0.1.0 255.255.255.0'], 'command', 10 FROM labs l WHERE l.slug = 'dhcp-server-config' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
SELECT l.id, 3, 'Set default gateway and DNS', E'In the DHCP pool, set the default router to 10.0.1.1 and DNS server to 8.8.8.8.', 'default-router and dns-server commands', 'DHCP options tell clients which gateway and DNS server to use automatically.', 'R1', ARRAY['default-router 10.0.1.1', 'dns-server 8.8.8.8'], 'command', 10 FROM labs l WHERE l.slug = 'dhcp-server-config' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
SELECT l.id, 4, 'Verify DHCP bindings', E'Check active DHCP leases on **R1**.', 'show ip dhcp binding', 'The binding table shows which IPs have been leased, to which MAC address, and when they expire.', 'R1', ARRAY['show ip dhcp binding'], 'command', 10 FROM labs l WHERE l.slug = 'dhcp-server-config' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);

-- ============================================================
-- DNS Lab
-- ============================================================
SELECT l.id, 'R1', 'router', 'Cisco ISR 4321', 300, 100, '{}' FROM labs l WHERE l.slug = 'dns-resolution' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
SELECT l.id, 'DNS-SRV', 'dns_server', 'Linux Server', 300, 300, '{}' FROM labs l WHERE l.slug = 'dns-resolution' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'DNS-SRV');

SELECT l.id, 1, 'Enable DNS lookup', E'On **R1**, enable DNS name resolution.', 'ip domain-lookup', 'By default IOS tries to resolve unknown commands as hostnames. This enables explicit DNS.', 'R1', ARRAY['configure terminal', 'ip domain-lookup'], 'command', 10 FROM labs l WHERE l.slug = 'dns-resolution' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
SELECT l.id, 2, 'Set DNS server', E'Point **R1** to the DNS server at 10.0.1.100.', 'ip name-server 10.0.1.100', 'The name-server command tells the router where to send DNS queries.', 'R1', ARRAY['ip name-server 10.0.1.100'], 'command', 10 FROM labs l WHERE l.slug = 'dns-resolution' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
SELECT l.id, 3, 'Set domain name', E'Configure the default domain name as **lab.local** on **R1**.', 'ip domain-name lab.local', 'The domain name is appended to unqualified hostnames for DNS lookups.', 'R1', ARRAY['ip domain-name lab.local'], 'command', 10 FROM labs l WHERE l.slug = 'dns-resolution' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
SELECT l.id, 4, 'Create a static host entry', E'Add a static DNS mapping: **server1** resolves to 10.0.1.100.', 'ip host server1 10.0.1.100', 'Static host entries are resolved locally without querying the DNS server.', 'R1', ARRAY['ip host server1 10.0.1.100'], 'command', 10 FROM labs l WHERE l.slug = 'dns-resolution' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);

-- ============================================================
-- BGP Lab
-- ============================================================
SELECT l.id, 'R1', 'router', 'Cisco ISR 4331', 150, 150, '{"asn":65001}' FROM labs l WHERE l.slug = 'bgp-peering' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'R1');
SELECT l.id, 'ISP', 'router', 'Cisco ISR 4451', 500, 150, '{"asn":65000}' FROM labs l WHERE l.slug = 'bgp-peering' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'ISP');

SELECT l.id, 1, 'Start BGP process', E'On **R1**, start BGP with AS number 65001.', 'router bgp 65001', 'BGP uses AS numbers to identify routing domains. Private ASNs are 64512-65534.', 'R1', ARRAY['configure terminal', 'router bgp 65001'], 'command', 10 FROM labs l WHERE l.slug = 'bgp-peering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
SELECT l.id, 2, 'Configure eBGP neighbor', E'Add the ISP router (10.0.0.2) as an eBGP neighbor in AS 65000.', 'neighbor 10.0.0.2 remote-as 65000', 'eBGP peers are in different ASes. The remote-as must match the neighbor''s actual AS.', 'R1', ARRAY['neighbor 10.0.0.2 remote-as 65000'], 'command', 15 FROM labs l WHERE l.slug = 'bgp-peering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
SELECT l.id, 3, 'Advertise a prefix', E'Advertise the 192.168.1.0/24 network into BGP on **R1**.', 'network 192.168.1.0 mask 255.255.255.0', 'The network command in BGP advertises a prefix if it exists in the routing table.', 'R1', ARRAY['network 192.168.1.0 mask 255.255.255.0'], 'command', 10 FROM labs l WHERE l.slug = 'bgp-peering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);
SELECT l.id, 4, 'Verify BGP table', E'Check the BGP routing table on **R1**.', 'show ip bgp', 'The > symbol indicates the best path. * means the route is valid.', 'R1', ARRAY['show ip bgp'], 'command', 10 FROM labs l WHERE l.slug = 'bgp-peering' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 4);

-- ============================================================
-- MPLS Lab
-- ============================================================
SELECT l.id, 'PE1', 'router', 'Cisco ISR 4331', 150, 150, '{}' FROM labs l WHERE l.slug = 'mpls-label-switching' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'PE1');
SELECT l.id, 'P1', 'router', 'Cisco ISR 4451', 400, 150, '{}' FROM labs l WHERE l.slug = 'mpls-label-switching' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'P1');
SELECT l.id, 'PE2', 'router', 'Cisco ISR 4331', 650, 150, '{}' FROM labs l WHERE l.slug = 'mpls-label-switching' AND NOT EXISTS (SELECT 1 FROM devices d WHERE d.lab_id = l.id AND d.name = 'PE2');

SELECT l.id, 1, 'Enable MPLS globally', E'On **PE1**, enable MPLS IP on interface Gi0/0.', 'mpls ip under the interface', 'MPLS must be enabled on each interface that participates in label switching.', 'PE1', ARRAY['configure terminal', 'interface GigabitEthernet0/0', 'mpls ip'], 'command', 10 FROM labs l WHERE l.slug = 'mpls-label-switching' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 1);
SELECT l.id, 2, 'Enable MPLS on P1', E'Enable MPLS on both interfaces of **P1** (Gi0/0 and Gi0/1).', 'mpls ip on each interface', 'Core routers (P routers) switch based on labels without examining the IP header.', 'P1', ARRAY['configure terminal', 'interface GigabitEthernet0/0', 'mpls ip', 'interface GigabitEthernet0/1', 'mpls ip'], 'command', 15 FROM labs l WHERE l.slug = 'mpls-label-switching' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 2);
SELECT l.id, 3, 'Verify MPLS forwarding table', E'On **PE1**, examine the MPLS forwarding table.', 'show mpls forwarding-table', 'The LFIB shows local labels, outgoing labels, and next-hop interfaces.', 'PE1', ARRAY['show mpls forwarding-table'], 'command', 10 FROM labs l WHERE l.slug = 'mpls-label-switching' AND NOT EXISTS (SELECT 1 FROM lab_steps ls WHERE ls.lab_id = l.id AND ls.step_number = 3);

